mapper.select:
SELECT #{databaseId} AS database_id, s.schemaname || '.' || s.relname AS table_name, COALESCE(pv.phase, 'not_running') AS session_phase, CASE WHEN pv.heap_blks_total > 0 THEN (pv.heap_blks_scanned::NUMERIC / pv.heap_blks_total * 100) ELSE 0 END AS session_progress, (s.last_autovacuum > s.last_vacuum) AS autovacuum, -- pg_stat_activity의 backend_start를 사용하여 경과 시간 계산 COALESCE( EXTRACT(EPOCH FROM (NOW() - act.backend_start))::BIGINT, 0 ) AS elapsed_seconds, s.n_dead_tup AS dead_tuple_total FROM pg_stat_user_tables s LEFT JOIN pg_stat_progress_vacuum pv ON s.relid = pv.relid LEFT JOIN pg_stat_activity act ON pv.pid = act.pid WHERE s.schemaname NOT IN ('pg_catalog', 'information_schema')
AND s.relname = #{tableName}
AND (pv.phase IS NOT NULL OR s.n_dead_tup > 0) ORDER BY s.n_dead_tup DESC LIMIT 20
